import { joinSession } from '@github/copilot-sdk/extension';
import { execSync } from 'node:child_process';
import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { join } from 'node:path';

const COMMIT_CACHE_MAX = 100;

function resolveRepoRoot(cwd) {
  try {
    return execSync('git rev-parse --show-toplevel', {
      encoding: 'utf8',
      stdio: ['pipe', 'pipe', 'ignore'],
      cwd: cwd ?? process.cwd(),
    }).trim();
  } catch {
    return cwd ?? process.cwd();
  }
}

function getHeadSha(repoRoot) {
  try {
    return execSync('git rev-parse HEAD', { encoding: 'utf8', stdio: ['pipe', 'pipe', 'ignore'], cwd: repoRoot }).trim();
  } catch { return null; }
}

function readCommitCache(repoRoot) {
  try {
    const raw = readFileSync(join(repoRoot, '.holdpoint/checked-commits.json'), 'utf8');
    const parsed = JSON.parse(raw);
    return new Set(Array.isArray(parsed.verified) ? parsed.verified : []);
  } catch { return new Set(); }
}

function recordCommitCache(repoRoot, sha) {
  try {
    const existing = readCommitCache(repoRoot);
    const updated = [sha, ...[...existing].filter((s) => s !== sha)].slice(0, COMMIT_CACHE_MAX);
    const dir = join(repoRoot, '.holdpoint');
    mkdirSync(dir, { recursive: true });
    writeFileSync(join(dir, 'checked-commits.json'), JSON.stringify({ verified: updated }, null, 2) + '\n', 'utf8');
  } catch { /* non-fatal */ }
}

function getStagedFiles(repoRoot) {
  try {
    return execSync('git diff --cached --name-only', {
      encoding: 'utf8',
      stdio: ['pipe', 'pipe', 'ignore'],
      cwd: repoRoot,
    })
      .trim()
      .split('\n')
      .filter(Boolean);
  } catch {
    return [];
  }
}

function getLastCommitFiles(repoRoot) {
  try {
    return execSync('git diff --name-only HEAD~1 HEAD', {
      encoding: 'utf8',
      stdio: ['pipe', 'pipe', 'ignore'],
      cwd: repoRoot,
    })
      .trim()
      .split('\n')
      .filter(Boolean);
  } catch {
    return [];
  }
}

function matchesWhen(when, changedFiles, userPatterns) {
  if (!when) return true;
  if (changedFiles.includes('__all__') || changedFiles.length === 0) return true;
  const patterns = {
    frontend: [/\.(tsx|jsx|css|scss)$/, /tailwind\.config\./, /postcss\.config\./, /^apps\/(builder|web)\//],
    backend: [/(^|\/)api\//, /(^|\/)server\//, /(^|\/)routes\//, /(^|\/)controllers\//, /(^|\/)middleware\//, /^packages\/[^/]+\/src\//],
    prisma: [/\.prisma$/, /(^|\/)prisma\//],
    socket: [/(^|\/)socket\//, /(^|\/)ws\//, /(^|\/)websocket\//],
    visual: [/\.stories\.(tsx?|jsx?)$/, /(^|\/)__screenshots__\//, /\.snap$/],
    python: [/\.pyi?$/, /requirements[^/]*\.txt$/, /pyproject\.toml$/, /setup\.(py|cfg)$/, /(^|\/)Pipfile(\.lock)?$/, /uv\.lock$/, /pytest\.ini$/, /tox\.ini$/],
    go: [/\.go$/, /go\.(mod|sum)$/],
    rust: [/\.rs$/, /Cargo\.(toml|lock)$/],
    java: [/\.(java|kt)$/, /\.gradle(\.kts)?$/, /pom\.xml$/],
    ruby: [/\.rb$/, /(^|\/)Gemfile(\.lock)?$/, /(^|\/)Rakefile$/],
    database: [/\.sql$/, /(^|\/)(migrations?|migration)\//, /(^|\/)prisma\//, /\.prisma$/, /(^|\/)db\//, /(^|\/)database\//, /(^|\/)(seeds?|seed)\//, /alembic\.ini$/],
    testing: [/\.(test|spec)\.(tsx?|jsx?|py|rb|go)$/, /(^|\/)__tests__\//, /(^|\/)tests?\//, /(^|\/)spec\//],
    infra: [/(^|\/)Dockerfile(\..*)?$/, /(^|\/)docker-compose/, /\.(tf|tfvars|hcl)$/, /(^|\/)k8s\//, /(^|\/)kubernetes\//, /(^|\/)(helm|charts)\//, /\.dockerignore$/],
    ci: [/(^|\/)(\.github\/workflows|\.circleci)\//, /(^|\/)Jenkinsfile$/, /(^|\/)\.(gitlab-ci|travis|drone)\.yml$/],
    docs: [/\.(mdx|rst)$/, /(^|\/)(docs|documentation)\//],
    structural: [
      /(^|\/|\\)package\.json$/, /tsconfig[^/]*\.json$/, /requirements[^/]*\.txt$/, /pyproject\.toml$/,
      /(^|\/)Pipfile(\.lock)?$/, /setup\.(py|cfg)$/, /pytest\.ini$/, /tox\.ini$/, /go\.mod$/, /Cargo\.toml$/,
      /pom\.xml$/, /build\.gradle(\.kts)?$/, /(^|\/)Gemfile(\.lock)?$/, /vitest\.config\./, /jest\.config\./,
      /playwright\.config\./, /eslint\.config\./, /\.eslintrc/, /biome\.json$/, /prettier\.config\./, /\.prettierrc/,
      /next\.config\./, /(^|\/)Dockerfile/, /(^|\/)docker-compose[^/]*\.(yml|yaml)$/, /\.tf$/, /prisma\/schema\.prisma$/,
      /openapi\.(yaml|yml|json)$/, /\.github\/workflows\/[^/]+\.(yml|yaml)$/,
      /(^|\/)(\.circleci\/|Jenkinsfile$|\.gitlab-ci\.yml$|\.travis\.yml$)/,
    ],
  };
  if (when in patterns) {
    return changedFiles.some((f) => (patterns[when] ?? []).some((re) => re.test(f)));
  }
  if (userPatterns && when in userPatterns) {
    return changedFiles.some((f) => new RegExp(userPatterns[when]).test(f));
  }
  return changedFiles.some((f) => new RegExp(when).test(f));
}

function runCheck(check, repoRoot) {
  if (!check.cmd) return { status: 'pending' };
  try {
    const output = execSync(check.cmd, { encoding: 'utf8', timeout: 60000, stdio: 'pipe', cwd: repoRoot });
    return { status: 'pass', output };
  } catch (e) {
    return { status: 'fail', output: [e.stdout, e.stderr].filter(Boolean).join('\n'), exitCode: e.status ?? 1 };
  }
}

const session = await joinSession({
  hooks: {
    onPreToolUse: async (input) => {
      if (input.toolName !== 'task_complete') return;

      try {
        const repoRoot = resolveRepoRoot(input.cwd);
        const stagedFiles = getStagedFiles(repoRoot);

        // Resolve effective file scope: staged → last commit → nothing (allow).
        // When falling back to the last commit, check the SHA cache first to
        // prevent the same commit being re-checked on every subsequent task_complete.
        let changedFiles;
        let headSha = null;
        if (stagedFiles.length > 0) {
          changedFiles = stagedFiles;
        } else {
          headSha = getHeadSha(repoRoot);
          if (headSha && readCommitCache(repoRoot).has(headSha)) {
            return; // already verified — allow task_complete
          }
          changedFiles = getLastCommitFiles(repoRoot);
          if (changedFiles.length === 0) return; // investigative session — allow
        }

        // Re-sync if checks.yaml is staged
        if (changedFiles.some((f) => /^checks\.yaml$/.test(f))) {
          await session.log('Holdpoint: checks.yaml changed — re-syncing engine files…', { ephemeral: true });
          const sync = runCheck({ cmd: 'npx holdpoint update' }, repoRoot);
          if (sync.status === 'fail') {
            return {
              permissionDecision: 'deny',
              permissionDecisionReason: `Holdpoint: checks.yaml changed but \`holdpoint update\` failed:\n\n${(sync.output ?? '').trim()}\n\nFix the error above, then retry.`,
            };
          }
        }

        const configPath = join(repoRoot, '.github/holdpoint/generated/checks.immutable.json');
        if (!existsSync(configPath)) {
          return {
            permissionDecision: 'deny',
            permissionDecisionReason: 'Holdpoint: .github/holdpoint/generated/checks.immutable.json not found — run: npx holdpoint update',
          };
        }

        const config = JSON.parse(readFileSync(configPath, 'utf8'));
        const applicable = config.checks.filter((c) => c.cmd !== undefined && matchesWhen(c.when, changedFiles, config.patterns));
        const failures = [];

        for (const check of applicable) {
          await session.log(`Holdpoint: running ${check.label}…`, { ephemeral: true });
          const result = runCheck(check, repoRoot);
          if (result.status === 'fail') failures.push({ check, result });
        }

        const promptChecks = config.checks.filter(
          (c) => c.prompt !== undefined && matchesWhen(c.when, changedFiles, config.patterns),
        );

        if (failures.length > 0) {
          const summary = failures.map((f) => `  ✗ [${f.check.label}]\n${(f.result.output ?? '').trim()}`).join('\n\n');
          const promptSection =
            promptChecks.length > 0
              ? `\n\nAlso carry out these agent prompts before committing:\n${promptChecks.map((c) => `  □ [${c.label}] ${c.prompt ?? ''}`).join('\n')}`
              : '';
          return {
            permissionDecision: 'deny',
            permissionDecisionReason: `Holdpoint: ${failures.length} check(s) failed:\n\n${summary}${promptSection}\n\nFix the above issues before marking the task complete.`,
          };
        }

        // Prompt checks are advisory — they cannot be auto-verified. Surface them as
        // reminders when cmd checks fail (above), but never block when all checks pass.

        // Record this commit as verified so subsequent task_complete calls skip re-checking.
        if (headSha) recordCommitCache(repoRoot, headSha);

        // Returning undefined allows task_complete to proceed
      } catch (err) {
        return {
          permissionDecision: 'deny',
          permissionDecisionReason: `Holdpoint extension error: ${err instanceof Error ? err.message : String(err)}`,
        };
      }
    },
  },
});
